//  contact side bar    with map 


import React, { useState, useEffect } from "react";
import api from "../../api/api";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { zodResolver } from "@hookform/resolvers/zod";
import { X, Pencil, Trash2, ArrowLeft } from "lucide-react";

import AddressInput from "./PlacesAutocomplete";
import ContactMap from "./map";

const contactValidation2 = z.object({
  name: z.string().min(1, "Name required"),
  email: z.string().email("Invalid email"),
  age: z
    .string()
    .min(1, "Age required")
    .regex(/^\d+$/, "Must be a number")
    .transform((val) => Number(val))
    .refine((val) => val >= 17, "Must be at least 17")
    .refine((val) => val <= 100, "Must be 100 or under"),
  tag: z.string().min(1, "Tag required"),
  phoneNumber: z.string().min(10, "Phone must be at least 10 digits"),
  address: z.string().min(5, "Address required"),
  lat: z.number().nullable().optional(),
  lng: z.number().nullable().optional(),
});

const TAG_STYLES = {
  VIP: "bg-amber-500/20 text-amber-400 border border-amber-500/30",
  VVIP: "bg-purple-500/20 text-purple-400 border border-purple-500/30",
  regular: "bg-emerald-500/20 text-emerald-400 border border-emerald-500/30",
};

// ── Read-only field card (matches your screenshot style) ──
const InfoCard = ({ label, children }) => (
  <div className="bg-slate-900/60 border border-slate-700 rounded-xl px-4 py-3">
    <p className="text-xs font-semibold text-slate-500 uppercase tracking-widest mb-1">
      {label}
    </p>
    <div className="text-white font-semibold text-sm">{children}</div>
  </div>
);

const ContactSidebar = ({
  selectedContact,
  setSelectedContact,
  fetchContacts,
  isLoaded,
}) => {
  const [mode, setMode] = useState("view"); // "view" | "edit"
  const [location, setLocation] = useState({ address: "", lat: null, lng: null });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [geoError, setGeoError] = useState("");

  const {
    register,
    handleSubmit,
    reset,
    setValue,
    formState: { errors },
  } = useForm({ resolver: zodResolver(contactValidation2) });

  // Reset form + mode when contact changes
  useEffect(() => {
    if (selectedContact) {
      setMode("view");
      setGeoError("");
      reset({
        name: selectedContact.name,
        email: selectedContact.email,
        age: String(selectedContact.age),
        tag: selectedContact.tag,
        phoneNumber: selectedContact.phoneNumber,
        address: selectedContact.address,
        lat: selectedContact.lat || null,
        lng: selectedContact.lng || null,
      });
      setLocation({
        address: selectedContact.address || "",
        lat: selectedContact.lat || null,
        lng: selectedContact.lng || null,
      });
    }
  }, [selectedContact, reset]);

  const handleClose = () => {
    setSelectedContact(null);
    setMode("view");
  };

  const handleDelete = async () => {
    if (!window.confirm("Delete this contact?")) return;
    setIsDeleting(true);
    try {
      await api.delete(`/contacts/${selectedContact.id}`);
      handleClose();
      fetchContacts();
    } catch (err) {
      console.error("Delete failed:", err);
    } finally {
      setIsDeleting(false);
    }
  };

  const onSubmit = async (data) => {
    if (!location.lat || !location.lng) {
      setGeoError("Please select a valid address from the suggestions.");
      return;
    }
    setGeoError("");
    setIsSubmitting(true);
    try {
      await api.put(`/contacts/${selectedContact.id}`, {
        ...data,
        lat: location.lat,
        lng: location.lng,
      });
      handleClose();
      fetchContacts();
    } catch (err) {
      console.error("Failed to save contact:", err);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <>
      {/* Backdrop */}
      <div
        className={`fixed inset-0 bg-black/60 backdrop-blur-sm z-40 transition-opacity duration-300 ${
          selectedContact
            ? "opacity-100 pointer-events-auto"
            : "opacity-0 pointer-events-none"
        }`}
        onClick={handleClose}
      />

      {/* Drawer */}
      <div
        className={`fixed top-0 right-0 h-full w-full max-w-md bg-slate-800 border-l border-slate-700 z-50 shadow-2xl flex flex-col transition-transform duration-300 ease-in-out ${
          selectedContact ? "translate-x-0" : "translate-x-full"
        }`}
      >
        {/* ── Header ── */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-slate-700 shrink-0">
          <div>
            {mode === "edit" && (
              <button
                onClick={() => setMode("view")}
                className="flex items-center gap-1 text-slate-400 hover:text-white text-xs mb-1 transition cursor-pointer"
              >
                <ArrowLeft size={12} /> Back
              </button>
            )}
            <p className="text-slate-400 text-xs font-semibold uppercase tracking-widest">
              {mode === "view" ? "Contact Details :" : "Edit Contact :"}
            </p>
            <h2 className="text-white font-bold text-xl mt-0.5">
              {selectedContact?.name}
            </h2>
          </div>
          <button
            onClick={handleClose}
            className="w-9 h-9 flex items-center justify-center rounded-full bg-slate-700 hover:bg-red-500 text-slate-400 hover:text-white transition cursor-pointer"
          >
            <X size={16} />
          </button>
        </div>

        {/* ── VIEW MODE ── */}
        {mode === "view" && selectedContact && (
          <div className="flex-1 overflow-y-auto p-6 space-y-3">
            <InfoCard label="Name">{selectedContact.name}</InfoCard>
            <InfoCard label="Email">
              <span className="text-blue-400">{selectedContact.email}</span>
            </InfoCard>
            <InfoCard label="Age">{selectedContact.age}</InfoCard>
            <InfoCard label="Tag">
              {selectedContact.tag ? (
                <span
                  className={`inline-block px-2.5 py-0.5 rounded-full text-xs font-semibold ${
                    TAG_STYLES[selectedContact.tag] ||
                    "bg-slate-700 text-slate-300"
                  }`}
                >
                  {selectedContact.tag}
                </span>
              ) : (
                <span className="text-slate-500">—</span>
              )}
            </InfoCard>
            <InfoCard label="Phone">{selectedContact.phoneNumber || "—"}</InfoCard>
            <InfoCard label="Address">
              <span className="text-slate-300 text-sm leading-relaxed">
                {selectedContact.address || "—"}
              </span>
            </InfoCard>

            {/* Map preview in view mode */}
            {selectedContact.lat && selectedContact.lng && (
              <ContactMap
                address={selectedContact.address}
                lat={selectedContact.lat}
                lng={selectedContact.lng}
                isLoaded={isLoaded}
              />
            )}

            {/* Edit + Delete buttons */}
            <div className="flex gap-3 pt-2">
              <button
                onClick={() => setMode("edit")}
                className="flex-1 flex items-center justify-center gap-2 py-3 rounded-xl bg-blue-600 hover:bg-blue-500 text-white text-sm font-bold transition cursor-pointer"
              >
                <Pencil size={15} />
                Edit
              </button>
              <button
                onClick={handleDelete}
                disabled={isDeleting}
                className="flex-1 flex items-center justify-center gap-2 py-3 rounded-xl bg-red-600 hover:bg-red-500 text-white text-sm font-bold disabled:opacity-50 transition cursor-pointer"
              >
                <Trash2 size={15} />
                {isDeleting ? "Deleting..." : "Delete"}
              </button>
            </div>
          </div>
        )}

        {/* ── EDIT MODE ── */}
        {mode === "edit" && selectedContact && (
          <form
            onSubmit={handleSubmit(onSubmit)}
            className="flex-1 overflow-y-auto p-6 space-y-4"
          >
            <div>
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1 block">
                Name
              </label>
              <input
                {...register("name")}
                placeholder="Name"
                className="w-full bg-slate-900 border border-slate-600 text-white rounded-xl px-4 py-2.5 outline-none focus:border-blue-500 transition"
              />
              {errors.name && (
                <p className="text-red-400 text-xs mt-1">{errors.name.message}</p>
              )}
            </div>

            <div>
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1 block">
                Email
              </label>
              <input
                {...register("email")}
                placeholder="Email"
                className="w-full bg-slate-900 border border-slate-600 text-white rounded-xl px-4 py-2.5 outline-none focus:border-blue-500 transition"
              />
              {errors.email && (
                <p className="text-red-400 text-xs mt-1">{errors.email.message}</p>
              )}
            </div>

            <div>
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1 block">
                Age
              </label>
              <input
                {...register("age")}
                placeholder="Age"
                className="w-full bg-slate-900 border border-slate-600 text-white rounded-xl px-4 py-2.5 outline-none focus:border-blue-500 transition"
              />
              {errors.age && (
                <p className="text-red-400 text-xs mt-1">{errors.age.message}</p>
              )}
            </div>

            <div>
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1 block">
                Tag
              </label>
              <select
                {...register("tag")}
                className="w-full bg-slate-900 border border-slate-600 text-white rounded-xl px-4 py-2.5 outline-none focus:border-blue-500 transition cursor-pointer"
              >
                <option value="">Select tag</option>
                <option value="VIP">VIP</option>
                <option value="VVIP">VVIP</option>
                <option value="regular">Regular</option>
              </select>
              {errors.tag && (
                <p className="text-red-400 text-xs mt-1">{errors.tag.message}</p>
              )}
            </div>

            <div>
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1 block">
                Phone
              </label>
              <input
                {...register("phoneNumber")}
                placeholder="Phone"
                className="w-full bg-slate-900 border border-slate-600 text-white rounded-xl px-4 py-2.5 outline-none focus:border-blue-500 transition"
              />
              {errors.phoneNumber && (
                <p className="text-red-400 text-xs mt-1">
                  {errors.phoneNumber.message}
                </p>
              )}
            </div>

            <div>
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1 block">
                Address
              </label>
              <div className="w-full bg-slate-900 border border-slate-600 rounded-xl px-4 py-2.5 focus-within:border-blue-500 transition">
                <AddressInput
                  value={location.address}
                  onChange={(val) => {
                    setLocation(val);
                    setValue("address", val.address);
                    setValue("lat", val.lat);
                    setValue("lng", val.lng);
                    setGeoError("");
                  }}
                />
              </div>
              {errors.address && (
                <p className="text-red-400 text-xs mt-1">
                  {errors.address.message}
                </p>
              )}
              {geoError && (
                <p className="text-red-400 text-xs mt-1">{geoError}</p>
              )}
            </div>

            <ContactMap
              address={location.address}
              lat={location.lat}
              lng={location.lng}
              isLoaded={isLoaded}
            />

            <div className="flex gap-3 pt-2">
              <button
                type="button"
                onClick={() => setMode("view")}
                className="flex-1 py-2.5 rounded-xl border border-slate-600 text-slate-300 text-sm font-semibold hover:bg-slate-700 transition cursor-pointer"
              >
                Cancel
              </button>
              <button
                type="submit"
                disabled={isSubmitting}
                className="flex-1 py-2.5 rounded-xl bg-blue-600 hover:bg-blue-500 text-white text-sm font-semibold disabled:opacity-50 transition cursor-pointer"
              >
                {isSubmitting ? "Saving..." : "Save Changes"}
              </button>
            </div>
          </form>
        )}
      </div>
    </>
  );
};

export default ContactSidebar;


--------------------------------------------------

contact with this    map :- 


import { useState, useEffect, useCallback } from "react";
import ContactFilter from "./ContactFilter";
import ContactSidebar from "./ContactSidebar";
import api from "../../api/api";
import { UserPlus, SlidersHorizontal, Search } from "lucide-react";
import ContactSkeleton from "./ContactSkeleton";
import ContactForm from "./ContactForm";

// ✅ FIX: accept isLoaded from parent (Sidebar → Contacts)
const Contacts = ({ isLoaded }) => {
  const [contacts, setContacts] = useState([]);
  const [selectedContact, setSelectedContact] = useState(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [search, setSearch] = useState("");
  const [showFilter, setShowFilter] = useState(false);
  const [filterField, setFilterField] = useState("");
  const [filterValue, setFilterValue] = useState("");
  const [currentPage, setCurrentPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(10);
  const [sortField, setSortField] = useState("name");
  const [sortOrder, setSortOrder] = useState("asc");

  // ✅ FIX: useCallback so fetchContacts is stable reference
  const fetchContacts = useCallback(async () => {
    setLoading(true);
    setError("");
    try {
      const response = await api.get("/contacts", {
        params: {
          search: search || undefined,
          field: filterField || undefined,
          value: filterValue || undefined,
        },
      });
      const data = response.data;
      setContacts(
        Array.isArray(data) ? data : data.data || data.contacts || []
      );
    } catch {
      setError("Failed to fetch contacts");
    } finally {
      // ✅ FIX: removed fake 2000ms delay — was always slowing down even on error
      setLoading(false);
    }
  }, [search, filterField, filterValue]);

  useEffect(() => {
    fetchContacts();
  }, [fetchContacts]); // ✅ FIX: fetchContacts in deps now safe via useCallback

  const handleContactAdded = () => {
    setIsFormOpen(false);
    fetchContacts();
  };

  const handlesearchChange = (e) => {
    setSearch(e.target.value);
    setCurrentPage(0);
  };

  const handleSort = (field) => {
    if (sortField === field) setSortOrder(sortOrder === "asc" ? "desc" : "asc");
    else {
      setSortField(field);
      setSortOrder("asc");
    }
    setCurrentPage(0);
  };

  const sortIcon = (field) => {
    if (sortField !== field) return " ↕";
    return sortOrder === "asc" ? " ↑" : " ↓";
  };

  const sorted = [...contacts].sort((a, b) => {
    const valA = (a[sortField] ?? "").toString().toLowerCase();
    const valB = (b[sortField] ?? "").toString().toLowerCase();
    if (sortOrder === "asc") return valA > valB ? 1 : -1;
    if (sortOrder === "desc") return valA < valB ? 1 : -1;
    return 0;
  });

  const totalContacts = sorted.length;
  const noOfPages = Math.ceil(totalContacts / rowsPerPage);
  const start = currentPage * rowsPerPage;
  const end = start + rowsPerPage;
  const paginatedContacts = sorted.slice(start, end);

  const handleRowsPerPageChange = (e) => {
    setRowsPerPage(Number(e.target.value));
    setCurrentPage(0);
  };

  const TAG_STYLES = {
    VIP: "bg-amber-100 text-amber-700 border border-amber-200",
    VVIP: "bg-purple-100 text-purple-700 border border-purple-200",
    regular: "bg-emerald-100 text-emerald-700 border border-emerald-200",
  };

  const SortTh = ({ field, label }) => (
    <th
      onClick={() => handleSort(field)}
      className="px-4 py-3 text-left text-xs font-semibold text-slate-400 uppercase tracking-wider cursor-pointer select-none hover:text-blue-400 transition-colors"
    >
      {label}
      <span className={sortField === field ? "text-blue-400 ml-1" : "text-slate-600 ml-1"}>
        {sortIcon(field)}
      </span>
    </th>
  );

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 p-6">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-white tracking-tight">
          Contact Management
        </h1>
        <p className="text-slate-400 text-sm mt-1">
          Manage and organise your contacts
        </p>
      </div>

      {/* Toolbar */}
      <div className="flex items-center gap-3 mb-6 flex-wrap">
        <button
          onClick={() => setShowFilter(true)}
          className="flex items-center gap-2 px-4 py-3 rounded-xl border border-slate-700 bg-slate-800 text-slate-300 text-sm font-bold hover:bg-slate-700 hover:border-slate-600 hover:text-white transition-all cursor-pointer w-38"
        >
          <SlidersHorizontal size={15} />
          Filter
        </button>

        <div className="flex flex-1 max-w-2xl items-center gap-2.5 rounded-xl border border-slate-700 bg-slate-800 font-bold px-3 py-2.5 focus-within:ring-2 focus-within:ring-blue-500/40 focus-within:border-blue-500/70 hover:border-slate-600 transition-colors">
          <Search size={15} className="text-slate-500 shrink-0" />
          <input
            type="search"
            placeholder="Search contacts..."
            value={search}
            onChange={handlesearchChange}
            className="w-full bg-transparent text-sm text-slate-100 placeholder-slate-500 outline-none"
          />
        </div>

        <button
          onClick={() => setIsFormOpen(true)}
          className="flex items-center gap-2 p-3 border border-zinc-700 border-2 w-40 rounded-lg bg-linear-to-r from-blue-500 to-orange-200 text-gray-800 text-sm font-semibold hover:from-mist-600 hover:to-indigo-400 hover:text-black border hover:border-black active:scale-[0.98] transition-all shadow-lg shadow-blue-500/20 cursor-pointer"
        >
          <UserPlus size={15} />
          Add Contact
        </button>
      </div>

      {/* Error */}
      {error && (
        <div className="flex items-center gap-2 bg-red-500/10 border border-red-500/30 text-red-400 rounded-xl px-4 py-3 text-sm mb-5">
          <span className="w-1.5 h-1.5 rounded-full bg-red-400 shrink-0" />
          {error}
        </div>
      )}

      {loading && <ContactSkeleton />}

      {!loading && (
        <>
          {/* Table */}
          <div className="bg-slate-800 border border-slate-700 rounded-md shadow-xl overflow-hidden">
            <div className="overflow-x-auto">
              <table className="min-w-full text-sm">
                <thead className="bg-slate-900/60 border-b border-slate-700">
                  <tr>
                    <th className="px-4 py-3">
                      <input type="checkbox" className="accent-blue-500 w-4 h-4" />
                    </th>
                    <SortTh field="name" label="Name" />
                    <SortTh field="email" label="Email" />
                    <SortTh field="age" label="Age" />
                    <SortTh field="tag" label="Tag" />
                    <SortTh field="phoneNumber" label="Mobile" />
                    <SortTh field="address" label="Address" />
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-700/50">
                  {paginatedContacts.length > 0 ? (
                    paginatedContacts.map((contact) => (
                      <tr
                        key={contact.id}
                        onClick={() => setSelectedContact(contact)}
                        className="hover:bg-slate-700/50 cursor-pointer transition-colors"
                      >
                        <td className="px-4 py-3">
                          <input
                            type="checkbox"
                            className="accent-blue-500 w-4 h-4"
                            onClick={(e) => e.stopPropagation()}
                          />
                        </td>
                        <td className="px-4 py-3 font-medium text-slate-100">{contact.name}</td>
                        <td className="px-4 py-3 text-blue-400">{contact.email}</td>
                        <td className="px-4 py-3 text-slate-300">{contact.age}</td>
                        <td className="px-4 py-3">
                          {contact.tag ? (
                            <span className={`inline-block px-2.5 py-0.5 rounded-full text-xs font-semibold ${TAG_STYLES[contact.tag] || "bg-slate-700 text-slate-300"}`}>
                              {contact.tag}
                            </span>
                          ) : (
                            <span className="text-slate-600">—</span>
                          )}
                        </td>
                        <td className="px-4 py-3 text-slate-300">{contact.phoneNumber || "—"}</td>
                        <td className="px-4 py-3 text-slate-400 max-w-xs truncate">{contact.address || "—"}</td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan={7} className="px-4 py-12 text-center text-slate-500">
                        {search ? "No contacts match your search" : "No contacts found — click Add Contact"}
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>

            {/* Footer */}
            <div className="px-5 py-3 border-t border-slate-700 flex items-center justify-between flex-wrap gap-3 bg-slate-900/40">
              <span className="text-xs text-slate-400">
                Showing{" "}
                <strong className="text-slate-200">
                  {totalContacts === 0 ? 0 : start + 1}–{Math.min(end, totalContacts)}
                </strong>{" "}
                of <strong className="text-slate-200">{totalContacts}</strong> contacts
              </span>

              <div className="flex items-center gap-2 text-xs text-slate-400">
                <span>Rows per page:</span>
                <select
                  value={rowsPerPage}
                  onChange={handleRowsPerPageChange}
                  className="bg-slate-800 border border-slate-600 text-slate-200 text-xs rounded-lg px-2 py-1.5 outline-none cursor-pointer"
                >
                  <option value={3}>3</option>
                  <option value={5}>5</option>
                  <option value={10}>10</option>
                  <option value={20}>20</option>
                </select>
              </div>

              <div className="flex items-center gap-2">
                <button
                  onClick={() => setCurrentPage((p) => p - 1)}
                  disabled={currentPage === 0}
                  className="px-3 py-1.5 rounded-lg border border-slate-600 text-slate-300 text-xs font-medium hover:bg-slate-700 disabled:opacity-30 disabled:cursor-not-allowed transition-all cursor-pointer"
                >
                  ← Prev
                </button>
                <span className="text-xs text-slate-400 font-medium">
                  Page <strong className="text-slate-200">{currentPage + 1}</strong> of{" "}
                  <strong className="text-slate-200">{Math.max(noOfPages, 1)}</strong>
                </span>
                <button
                  onClick={() => setCurrentPage((p) => p + 1)}
                  disabled={currentPage >= noOfPages - 1}
                  className="px-3 py-1.5 rounded-lg border border-slate-600 text-slate-300 text-xs font-medium hover:bg-slate-700 disabled:opacity-30 disabled:cursor-not-allowed transition-all cursor-pointer"
                >
                  Next →
                </button>
              </div>
            </div>
          </div>

          {/* Filter Panel */}
          {showFilter && (
            <div className="absolute top-40 z-50">
              <div className="bg-slate-800 border border-slate-700 rounded-2xl shadow-2xl p-4 w-96">
                <button
                  onClick={() => setShowFilter(false)}
                  className="absolute top-3 right-3 w-7 h-7 flex items-center justify-center rounded-full bg-slate-700 hover:bg-red-500 hover:text-white text-slate-400 text-xs transition cursor-pointer"
                >
                  ✕
                </button>
                <ContactFilter
                  setFilterField={setFilterField}
                  setFilterValue={setFilterValue}
                  close={() => setShowFilter(false)}
                />
              </div>
            </div>
          )}

          {/* Add Contact Modal */}
          {isFormOpen && (
            <div
              className="fixed inset-0 bg-black/70 backdrop-blur-sm z-50 flex items-center justify-center p-4"
              onClick={() => setIsFormOpen(false)}
            >
              <div
                className="relative w-full max-w-md bg-slate-800 border border-slate-700 rounded-2xl shadow-2xl max-h-[93vh] flex flex-col overflow-hidden"
                onClick={(e) => e.stopPropagation()}
              >
                <div className="overflow-y-auto flex-1">
                  <ContactForm onSuccess={handleContactAdded} close={() => setIsFormOpen(false)} />
                </div>
              </div>
            </div>
          )}

          {/* ✅ FIX: isLoaded now passed to ContactSidebar so map works */}
          <ContactSidebar
            selectedContact={selectedContact}
            setSelectedContact={setSelectedContact}
            fetchContacts={fetchContacts}
            isLoaded={isLoaded}
          />
        </>
      )}
    </div>
  );
};

export default Contacts;



