import React, { useContext } from "react";
import { createBrowserRouter, RouterProvider, Navigate } from "react-router-dom";
import { useLoadScript } from "@react-google-maps/api"; // ✅ FIX: moved here

import Signup from "./pages/signup/Signup";
import Home from "./pages/home/Home";
import Login from "./pages/login/Login";
import ContactForm from "./pages/contacts/ContactForm";
import EmployeeForm from "./pages/employee/EmployeeForm";
import UserProfile from "./pages/user-profile/UserProfile";
import Contacts from "./pages/contacts/Contacts";
import Employees from "./pages/employee/Employees";
import Sidebar from "./components/Sidebar";
import { AuthContext } from "./Authcontext/AuthContext";

// ✅ FIX: outside component — stable reference
const libraries = ["places"];
const ProtectedLayout = () => {
  const { token } = useContext(AuthContext);


const { isLoaded } = useLoadScript({
  googleMapsApiKey: import.meta.env.VITE_GOOGLE_MAPS_API_KEY,
  libraries,
  version: "weekly", // ✅ ADD THIS — ensures latest Places API is loaded
});

  if (!token) {
    return <Navigate to="/login" replace />; // ✅ FIX: was commented out
  }

  return <Sidebar isLoaded={isLoaded} />; // ✅ FIX: isLoaded passed down
};

const PublicRoute = ({ children }) => {
  const { token } = useContext(AuthContext);
  if (token) return <Navigate to="/" replace />;
  return children;
};

const router = createBrowserRouter([
  {
    path: "/",
    element: <ProtectedLayout />,
    children: [
      { path: "",              element: <Home />         },
      { path: "contacts",      element: <Contacts />     },
      { path: "contact-form",  element: <ContactForm />  },
      { path: "employees",     element: <Employees />    },
      { path: "employee-form", element: <EmployeeForm /> },
      { path: "profile",       element: <UserProfile />  },
    ],
  },
  { path: "/login",  element: <PublicRoute><Login /></PublicRoute>  },
  { path: "/signup", element: <PublicRoute><Signup /></PublicRoute> },
]);

function App() {
  return <RouterProvider router={router} />;
}

export default App;